// Validar y preparar entrada
const inputData = $input.first().json;

// Validar parámetros requeridos
if (!inputData.type) {
  throw new Error('El parámetro type es requerido');
}

if (!inputData.variables) {
  throw new Error('El parámetro variables es requerido');
}

// Validar tipos de documento permitidos
const allowedTypes = ['demanda_laboral', 'carta_documento', 'contrato_servicios', 'escrito_presentacion'];
if (!allowedTypes.includes(inputData.type)) {
  throw new Error(`Tipo de documento no válido. Permitidos: ${allowedTypes.join(', ')}`);
}

// Preparar datos de entrada
const documentType = inputData.type;
const caseId = inputData.case_id || null;
const variables = inputData.variables || {};

return {
  json: {
    document_type: documentType,
    case_id: caseId,
    variables: variables,
    start_time: Date.now()
  }
};

// Combinar plantilla, variables y contexto
const templateData = $('Obtener Plantilla').first().json;
const inputData = $('Validar y Preparar Entrada').first().json;
const caseContext = $('Obtener Contexto del Caso').first().json;

// Obtener plantilla
const template = templateData.body_md;
const promptVars = templateData.prompt_vars;
const variables = inputData.variables;

// Reemplazar variables en la plantilla
let finalTemplate = template;
for (const [key, value] of Object.entries(variables)) {
  const placeholder = `{{${key}}}`;
  finalTemplate = finalTemplate.replace(new RegExp(placeholder, 'g'), value);
}

// Preparar contexto adicional del caso
let caseContextText = '';
if (caseContext && caseContext.success && caseContext.answer_md) {
  caseContextText = `\n\n## CONTEXTO ADICIONAL DEL CASO\n\n${caseContext.answer_md}\n\n**Citas:**\n`;
  if (caseContext.citations && caseContext.citations.length > 0) {
    caseContext.citations.forEach(citation => {
      caseContextText += `- ${citation.fuente}:${citation.documento}:${citation.page} (score=${citation.score})\n`;
    });
  }
}

// Construir prompt para el LLM redactor
const systemPrompt = `Eres abogado redactor en Mendoza. Redacta escritos con formato procesal argentino.
Estructura: Personería y Competencia; Hechos; Derecho (citas del contexto); Petitorio; Prueba; Reserva de Caso Federal (si aplica).
Cita {fuente}:{documento}:{pagina} sólo si está en el contexto.
No inventes datos; deja TODO: ... donde falte completar.
Devuelve en Markdown bien formateado.`;

const userPrompt = `Redacta el siguiente documento legal usando la plantilla base y el contexto proporcionado:\n\n## PLANTILLA BASE\n\n${finalTemplate}\n\n${caseContextText}\n\n## VARIABLES PROPORCIONADAS\n\n${JSON.stringify(variables, null, 2)}`;

return {
  json: {
    document_type: inputData.document_type,
    case_id: inputData.case_id,
    template: finalTemplate,
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    case_context: caseContext,
    start_time: inputData.start_time
  }
};

